// Quebra a janela em N requests de 1 dia, contornando o timeout 524 da UTMify.
// Lê DIAS_BUSCA, TMX_TOKEN, OFFER_ID, UTMIFY_DASHBOARD_ID do node Config.

const config = $('⚙️ Config').first().json;
const token = $json.auth.token;
const dias = Number(config.DIAS_BUSCA) || 30;

const agora = new Date();
const inicio = new Date(agora);
inicio.setUTCDate(inicio.getUTCDate() - dias);
inicio.setUTCHours(0, 0, 0, 0);

const janelas = [];
let cursor = new Date(inicio);
while (cursor < agora) {
  const fim = new Date(cursor);
  fim.setUTCDate(fim.getUTCDate() + 1);
  janelas.push({
    json: {
      _utmifyToken: token,
      _dashboardId: config.UTMIFY_DASHBOARD_ID,
      _tmxApiUrl: config.TMX_API_URL,
      _tmxToken: config.TMX_TOKEN,
      _offerId: config.OFFER_ID,
      dateFrom: cursor.toISOString(),
      dateTo: (fim > agora ? agora : fim).toISOString(),
      _date: cursor.toISOString().slice(0, 10),
      _janela: janelas.length + 1,
    },
  });
  cursor.setUTCDate(cursor.getUTCDate() + 1);
}
return janelas;

// Agrega resultados das N janelas diárias em UM snapshot por dia,
// no formato que o TMX HUB aceita em /v1/offers/:id/ingest.
//
// IMPORTANTE: o node HTTP 'Buscar dia' substitui o input pelos campos da
// resposta — perdemos _date, _offerId, etc. Por isso recuperamos a data
// via itemMatching(i) do node de janelas, que é o jeito n8n-nativo.
//
// Os nomes de campo (item.spend, item.salesCount, etc) seguem o que o
// workflow [FB] - Automação Planilhas usa há tempos com sucesso.
// UTMify devolve valores monetários em CENTAVOS — dividir /100 vira BRL.

const config = $('⚙️ Config').first().json;
const items = $input.all();
const windowsNode = $('📅 Quebrar em janelas diárias');
const byDate = new Map();

function n(v) {
  const x = Number(v);
  return Number.isFinite(x) ? x : 0;
}

for (let i = 0; i < items.length; i++) {
  const it = items[i];

  // Continue-on-error pode injetar item de erro — pula.
  if (it.json && (it.json.error || it.json.errorMessage || it.json.code === 'ERR_BAD_RESPONSE')) {
    continue;
  }

  // Recupera a data da janela correspondente (input → output pareados).
  let date = null;
  try {
    const win = windowsNode.itemMatching(i);
    date = win && win.json ? win.json._date : null;
  } catch (_) {
    date = null;
  }
  if (!date) continue;

  const results = (it.json && it.json.results) || [];

  if (!byDate.has(date)) {
    byDate.set(date, {
      date,
      spend: 0, sales: 0, revenue: 0, ic: 0,
      impressions: 0, clicks: 0,
      adsets: [],
    });
  }
  const day = byDate.get(date);

  for (const r of results) {
    // Mesmos field names do [FB] - Automação Planilhas (campos confirmados).
    const spendCents = n(r.spend);
    // Receita/profit não é usada no [FB], então ainda tentamos múltiplos nomes.
    const revenueCents = n(r.revenue) || n(r.grossRevenue) || n(r.totalRevenue) || n(r.profit);
    const sales = n(r.salesCount) || n(r.frontSalesCount) || n(r.sales) || n(r.orderCount);
    const ic = n(r.initiateCheckoutCount) || n(r.initiateCheckout) || n(r.initiate_checkout);
    const impressions = n(r.impressions);
    const clicks = n(r.inlineLinkClicks) || n(r.clicks) || n(r.linkClicks);

    // Inclui adset se teve QUALQUER atividade (gasto sem venda também conta).
    if (spendCents === 0 && sales === 0 && revenueCents === 0 && ic === 0 && impressions === 0) {
      continue;
    }

    const adset = {
      name: String(r.name || r.adsetName || '(sem nome)').slice(0, 200),
      spend: spendCents / 100,
      revenue: revenueCents / 100,
      sales,
      ic,
    };
    if (impressions) adset.impressions = impressions;
    if (clicks) adset.clicks = clicks;
    day.adsets.push(adset);

    day.spend += adset.spend;
    day.revenue += adset.revenue;
    day.sales += sales;
    day.ic += ic;
    day.impressions += impressions;
    day.clicks += clicks;
  }
}

// Mantém só dias com QUALQUER atividade — dias 100% zerados não servem.
const snapshots = Array.from(byDate.values())
  .filter((d) => d.spend > 0 || d.sales > 0 || d.revenue > 0 || d.ic > 0 || d.impressions > 0)
  .map((d) => {
    if (d.impressions === 0) delete d.impressions;
    if (d.clicks === 0) delete d.clicks;
    if (!d.adsets || d.adsets.length === 0) delete d.adsets;
    return d;
  });

const when = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
console.log('[' + when + '] 📊 snapshots montados:', snapshots.length, 'dias');
if (snapshots.length > 0) {
  const totalSpend = snapshots.reduce((s, d) => s + d.spend, 0).toFixed(2);
  const totalSales = snapshots.reduce((s, d) => s + d.sales, 0);
  console.log('  → spend total: R$', totalSpend, '| vendas:', totalSales);
}

if (snapshots.length === 0) {
  return [{ json: { _empty: true, _config: config } }];
}

return [
  {
    json: {
      _tmxApiUrl: config.TMX_API_URL,
      _tmxToken: config.TMX_TOKEN,
      _offerId: config.OFFER_ID,
      payload: { snapshots },
    },
  },
];

const r = $json;
const when = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
console.log('[' + when + '] ✅ TMX ingest', { ingested: r.ingested, dates: r.dates });
return { json: { status: 'ok', when, ...r } };
